function ChartGridSparklineRow() {
  const { div, span } = tags;
  const metrics = [
    { label: 'Revenue', value: '$12.4k', spark: [42, 48, 51, 45, 62, 58, 72], color: 'success' },
    { label: 'Users', value: '8.4k', spark: [320, 340, 310, 380, 420, 450, 480], color: 'primary' },
    { label: 'Bounce Rate', value: '42%', spark: [48, 45, 50, 42, 44, 40, 38], color: 'warning' },
    { label: 'Latency', value: '124ms', spark: [130, 125, 140, 128, 118, 122, 124], color: 'error' }
  ];

  return div({ class: css('_grid _gc2 _md:gc4 _gap3') },
    ...metrics.map(m =>
      div({ class: css('_flex _col _gap2 _p3 _bgmuted/5 _r2') },
        span({ class: css('_textxs _fgmuted') }, m.label),
        span({ class: css('_textlg _bold') }, m.value),
        Sparkline({ data: m.spark, height: 32, color: m.color })
      )
    )
  );
}

